import{c as s,Q as a,j as n,m as o}from"./chunks/framework.CBiVa4O3.js";const h=JSON.parse('{"title":"拜占庭容错","description":"","frontmatter":{},"headers":[],"relativePath":"../distributedLearning/15-拜占庭容错.md","filePath":"../distributedLearning/15-拜占庭容错.md","lastUpdated":1778496697000}'),r={name:"../distributedLearning/15-拜占庭容错.md"};function e(p,t,l,i,d,g){return a(),n("div",null,[...t[0]||(t[0]=[o(`<h1 id="拜占庭容错" tabindex="-1">拜占庭容错 <a class="header-anchor" href="#拜占庭容错" aria-label="Permalink to &quot;拜占庭容错&quot;">​</a></h1><p>到这里为止,前 14 篇讲的所有共识协议——Paxos、Raft、ZAB、EPaxos——<strong>都假设节点是&quot;诚实&quot;的</strong>。<strong>节点要么正常工作,要么直接挂掉(crash-stop)</strong>,<strong>它不会撒谎、不会伪造消息、不会被攻击者控制</strong>。<strong>这个假设在内网集群里基本成立</strong>,所以 Raft / Paxos 才能用 N ≥ 2f+1 的多数派搞定。<strong>但金融监管系统、联盟链、跨组织协作、公链——一旦节点不再都属于&quot;自己&quot;</strong>,<strong>有节点可能被攻击、被收买、硬件出错返回脏数据</strong>,<strong>Raft 就完全失效</strong>——<strong>一个撒谎的 leader 能让整个集群相信&quot;账户余额是 0&quot;</strong>。<strong>这就是拜占庭故障(Byzantine fault),也是公链 / 联盟链 / 容灾级金融为什么要用一套完全不同的协议——PBFT / HotStuff / Tendermint</strong>。</p><blockquote><p>一句话先记住:<strong>拜占庭故障 = 节点可任意行为(撒谎 / 伪造 / 攻击 / 硬件错),共识需要 N ≥ 3f+1</strong>(诚实节点超过 2/3)。<strong>PBFT(Castro-Liskov 1999)三阶段 Pre-prepare / Prepare / Commit,O(N²) 消息复杂度</strong>;<strong>HotStuff(Yin 2019)链式 BFT,O(N) 改进</strong>;<strong>Tendermint / Cosmos = PBFT + 轮换 leader + PoS,工业代表</strong>。<strong>公链 PoW/PoS 不是严格 BFT——概率最终性,性能远不如 PBFT</strong>。<strong>谁需要 BFT:联盟链 / 公链 / 极个别金融容灾</strong>;<strong>99% 的业务不需要——内网集群 Paxos/Raft 足够,BFT 是 3-5 倍开销的奢侈品</strong>。</p></blockquote><hr><h2 id="一、拜占庭故障是什么" tabindex="-1">一、拜占庭故障是什么 <a class="header-anchor" href="#一、拜占庭故障是什么" aria-label="Permalink to &quot;一、拜占庭故障是什么&quot;">​</a></h2><h3 id="_1-1-故障模型谱" tabindex="-1">1.1 故障模型谱 <a class="header-anchor" href="#_1-1-故障模型谱" aria-label="Permalink to &quot;1.1 故障模型谱&quot;">​</a></h3><p>第 2 篇讲过故障模型(回忆下):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>故障模型从宽到严:</span></span>
<span class="line"><span>    Crash-stop      节点要么正常,要么挂掉,挂了不恢复</span></span>
<span class="line"><span>    Crash-recovery  挂了能恢复,日志还在(Raft / Paxos 假设)</span></span>
<span class="line"><span>    Omission        消息可能丢失(网络分区,前 14 篇都假设)</span></span>
<span class="line"><span>    Byzantine       节点可以任意行为(包括撒谎、伪造、攻击)</span></span></code></pre></div><p><strong>拜占庭是最严格的故障模型</strong>——<strong>它假设节点是敌对的</strong>,<strong>可以发任意消息给任意人</strong>。</p><h3 id="_1-2-名字的由来" tabindex="-1">1.2 名字的由来 <a class="header-anchor" href="#_1-2-名字的由来" aria-label="Permalink to &quot;1.2 名字的由来&quot;">​</a></h3><p>Lamport / Shostak / Pease 1982 论文 <strong>&quot;The Byzantine Generals Problem&quot;</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>故事:几个拜占庭将军围攻一座城,他们必须就&quot;进攻 or 撤退&quot;达成一致</span></span>
<span class="line"><span>      但他们只能通过信使通信</span></span>
<span class="line"><span>      信使可能叛变(消息篡改/伪造)</span></span>
<span class="line"><span>      将军本身也可能叛变(发不同消息给不同将军)</span></span>
<span class="line"><span>      问题:在 f 个叛变将军的情况下,忠诚将军如何达成一致?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>证明:N ≥ 3f+1 是充要条件(其中 f 是叛变将军数)</span></span></code></pre></div><p><strong>Lamport 取拜占庭这个名字,因为它够&quot;陌生&quot;</strong>——他想避免任何政治敏感(Albanian Generals 之类),拜占庭帝国是中世纪东罗马,跟现实政治无瓜葛。</p><h3 id="_1-3-真实世界的拜占庭故障来源" tabindex="-1">1.3 真实世界的拜占庭故障来源 <a class="header-anchor" href="#_1-3-真实世界的拜占庭故障来源" aria-label="Permalink to &quot;1.3 真实世界的拜占庭故障来源&quot;">​</a></h3><p><strong>不只是恶意攻击</strong>,包括:</p><table tabindex="0"><thead><tr><th>来源</th><th>例子</th></tr></thead><tbody><tr><td><strong>硬件错误</strong></td><td>内存位翻转、磁盘静默损坏、CPU 计算错(intel Pentium FDIV bug)</td></tr><tr><td><strong>网络中间人</strong></td><td>TLS 不强制 / 中间人篡改 / 路由器劫持</td></tr><tr><td><strong>代码 bug</strong></td><td>不同版本节点行为不一致(升级期间)</td></tr><tr><td><strong>配置错误</strong></td><td>节点配置不同,行为不可预测</td></tr><tr><td><strong>恶意攻击</strong></td><td>节点被入侵,有意发错消息</td></tr><tr><td><strong>多方共建</strong></td><td>不同组织部署的节点,互不信任</td></tr></tbody></table><blockquote><p><strong>联盟链场景</strong>:几家银行共建一个清算网络,<strong>每家都可能&quot;为了自己利益&quot;作弊</strong>。<strong>这不是技术,是商业现实</strong>——没有任何一家银行愿意把账本完全托管给另一家。<strong>BFT 的本质是&quot;在互不信任的多方间达成一致&quot;</strong>。</p></blockquote><hr><h2 id="二、n-≥-3f-1-的证明直觉" tabindex="-1">二、N ≥ 3f+1 的证明直觉 <a class="header-anchor" href="#二、n-≥-3f-1-的证明直觉" aria-label="Permalink to &quot;二、N ≥ 3f+1 的证明直觉&quot;">​</a></h2><p>为什么是 3f+1,不是 2f+1?Lamport 论文给了严格证明,这里给个<strong>直观解释</strong>。</p><h3 id="_2-1-crash-模型-为什么-2f-1-够" tabindex="-1">2.1 Crash 模型:为什么 2f+1 够 <a class="header-anchor" href="#_2-1-crash-模型-为什么-2f-1-够" aria-label="Permalink to &quot;2.1 Crash 模型:为什么 2f+1 够&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>N = 2f+1 个节点,最多 f 个 crash</span></span>
<span class="line"><span></span></span>
<span class="line"><span>任何决策需多数派(f+1 个) ack</span></span>
<span class="line"><span>即使 f 个挂了,还有 f+1 个能 ack</span></span>
<span class="line"><span>两个不同多数派必有交集,且交集节点诚实(它&quot;不挂时&quot;答案一致)</span></span>
<span class="line"><span>→ 一致性保证</span></span></code></pre></div><p><strong>关键</strong>:crash 节点要么正常工作,要么不工作——<strong>它不会&quot;看起来工作但给错答案&quot;</strong>。</p><h3 id="_2-2-byzantine-模型-为什么需要-3f-1" tabindex="-1">2.2 Byzantine 模型:为什么需要 3f+1 <a class="header-anchor" href="#_2-2-byzantine-模型-为什么需要-3f-1" aria-label="Permalink to &quot;2.2 Byzantine 模型:为什么需要 3f+1&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>N = 2f+1 不够,因为 f 个拜占庭节点可以&quot;假装&quot;任意答案</span></span>
<span class="line"><span></span></span>
<span class="line"><span>例:3 节点,1 拜占庭</span></span>
<span class="line"><span>    诚实节点 A:看到 x = 5,告诉 B 和 C </span></span>
<span class="line"><span>    诚实节点 C:看到 x = 5,告诉 A 和 B</span></span>
<span class="line"><span>    拜占庭 B:告诉 A &quot;x = 5&quot;,告诉 C &quot;x = 7&quot;</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    A 收到 (A: 5, B: 5, C: 5) → 一致,认为 x = 5</span></span>
<span class="line"><span>    C 收到 (A: 5, B: 7, C: 5) → 不一致,认为 x = 7?</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    一个节点说不同的话,诚实节点看到的&quot;多数派&quot;不同</span></span></code></pre></div><p><strong>N ≥ 3f+1 的必要性</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>N 节点,f 拜占庭</span></span>
<span class="line"><span>诚实节点 = N - f</span></span>
<span class="line"><span>任何决策需要从 N - f 个 ack 中确定(因为拜占庭可以不回复 / 回错)</span></span>
<span class="line"><span>两个不同决策的诚实 ack 集合必有交集(才能保证一致)</span></span>
<span class="line"><span>    → (N - f) + (N - f) &gt; N - f</span></span>
<span class="line"><span>    → N &gt; 3f - f = 2f...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>但还要&quot;交集中至少有一个诚实节点&quot;:</span></span>
<span class="line"><span>    (N - f) + (N - f) - (N - f) &gt; f</span></span>
<span class="line"><span>    → N - f &gt; f</span></span>
<span class="line"><span>    → N &gt; 2f</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>再算上&quot;诚实节点占主导&quot;:</span></span>
<span class="line"><span>    N - f &gt; f + f</span></span>
<span class="line"><span>    → N &gt; 3f</span></span>
<span class="line"><span>    → N ≥ 3f + 1</span></span></code></pre></div><p><strong>直觉</strong>:<strong>诚实节点必须占严格多数(&gt; 2/3),才能&quot;投出来的票&quot;经得起拜占庭节点的搅局</strong>。</p><h3 id="_2-3-典型配置" tabindex="-1">2.3 典型配置 <a class="header-anchor" href="#_2-3-典型配置" aria-label="Permalink to &quot;2.3 典型配置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>f(可容忍拜占庭)</th><th>N(总节点)</th><th>应用</th></tr></thead><tbody><tr><td>f = 1</td><td><strong>N = 4</strong></td><td>最小 BFT(实际很少,容错太弱)</td></tr><tr><td>f = 2</td><td><strong>N = 7</strong></td><td>小型联盟链</td></tr><tr><td>f = 3</td><td><strong>N = 10</strong></td><td>中型联盟链</td></tr><tr><td>f = 10</td><td><strong>N = 31</strong></td><td>大型联盟链(Cosmos validator 数量级)</td></tr><tr><td>f = 100+</td><td><strong>N = 300+</strong></td><td>公链(以太坊 PoS、大型 Cosmos)</td></tr></tbody></table><blockquote><p><strong>节点数越多,通信复杂度越高</strong>——PBFT 是 O(N²),<strong>N = 100 时一次共识要发 10000 条消息,带宽爆炸</strong>。<strong>这是为什么公链都在改进消息复杂度</strong>(HotStuff、Aleph、Narwhal-Bullshark 等)。</p></blockquote><hr><h2 id="三、pbft-1999-年的里程碑" tabindex="-1">三、PBFT:1999 年的里程碑 <a class="header-anchor" href="#三、pbft-1999-年的里程碑" aria-label="Permalink to &quot;三、PBFT:1999 年的里程碑&quot;">​</a></h2><h3 id="_3-1-论文背景" tabindex="-1">3.1 论文背景 <a class="header-anchor" href="#_3-1-论文背景" aria-label="Permalink to &quot;3.1 论文背景&quot;">​</a></h3><p><strong>Practical Byzantine Fault Tolerance</strong>(Castro-Liskov, OSDI 1999)是 BFT 工程化的开端。<strong>1999 年之前的 BFT 协议都假设同步网络(消息延迟有上界),根本不实用</strong>。PBFT 的贡献:<strong>第一个在异步网络下实用的 BFT 协议</strong>。</p><p><strong>当时性能</strong>:</p><ul><li>100ms 级延迟(局域网)</li><li>千级 TPS(对 1999 年硬件来说很猛了)</li></ul><h3 id="_3-2-pbft-三阶段" tabindex="-1">3.2 PBFT 三阶段 <a class="header-anchor" href="#_3-2-pbft-三阶段" aria-label="Permalink to &quot;3.2 PBFT 三阶段&quot;">​</a></h3><p>PBFT 类似 Raft,<strong>有一个 primary(leader)</strong>,<strong>用三阶段完成一次共识</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>              Pre-prepare      Prepare        Commit</span></span>
<span class="line"><span>Client          │                │               │</span></span>
<span class="line"><span>  │ Request     │                │               │</span></span>
<span class="line"><span>  ├────────────▶│                │               │</span></span>
<span class="line"><span>  │             │ Pre-prepare    │               │</span></span>
<span class="line"><span>  │             ├──────[broadcast]──────────────▶│         所有节点</span></span>
<span class="line"><span>  │             │                │               │</span></span>
<span class="line"><span>  │             │                │ Prepare       │</span></span>
<span class="line"><span>  │             │                ├─[broadcast]──▶│         所有节点</span></span>
<span class="line"><span>  │             │                │ 收到 2f+1 个   │</span></span>
<span class="line"><span>  │             │                │ Prepare       │</span></span>
<span class="line"><span>  │             │                │               │ Commit</span></span>
<span class="line"><span>  │             │                │               ├─[broadcast]─▶</span></span>
<span class="line"><span>  │             │                │               │ 收到 2f+1 个</span></span>
<span class="line"><span>  │             │                │               │ Commit</span></span>
<span class="line"><span>  │             │                │               │ → execute</span></span>
<span class="line"><span>  │◀────── Reply ──────────────────────────────────────────────</span></span></code></pre></div><p>三阶段角色:</p><h4 id="pre-prepare-预准备" tabindex="-1">Pre-prepare(预准备) <a class="header-anchor" href="#pre-prepare-预准备" aria-label="Permalink to &quot;Pre-prepare(预准备)&quot;">​</a></h4><ul><li><strong>Primary</strong> 收到 client request,分配序号 n,发 <code>&lt;PRE-PREPARE, view, n, request&gt;</code> 给所有副本</li><li>副本收到 → 验证(签名、view、序号没冲突)→ 如 OK,进 Prepare</li></ul><p><strong>作用</strong>:由 primary 强加一个顺序——但 <strong>primary 可能撒谎</strong>(发不同消息给不同副本),所以需要下一阶段对齐。</p><h4 id="prepare-准备" tabindex="-1">Prepare(准备) <a class="header-anchor" href="#prepare-准备" aria-label="Permalink to &quot;Prepare(准备)&quot;">​</a></h4><ul><li>每个副本收到 Pre-prepare 后 → <strong>向所有其他副本广播 Prepare</strong></li><li>每个副本收集 <strong>≥ 2f 个其他副本的 Prepare(共 2f+1 含自己)</strong> → 进 prepared 状态</li></ul><p><strong>作用</strong>:<strong>确保多数派(2f+1)都同意&quot;primary 给的序号是这个 request 的&quot;</strong>——<strong>如果 primary 撒谎,不同副本看到的 Prepare 集合不同,prepared 状态不一致</strong>。<strong>但只要 2f+1 个一致,就说明诚实节点已经达成共识</strong>。</p><h4 id="commit-提交" tabindex="-1">Commit(提交) <a class="header-anchor" href="#commit-提交" aria-label="Permalink to &quot;Commit(提交)&quot;">​</a></h4><ul><li>副本进入 prepared 后 → <strong>广播 Commit</strong></li><li>每个副本收集 <strong>≥ 2f+1 个 Commit</strong> → 进 committed 状态</li><li>委托状态机执行 → 回 client</li></ul><p><strong>作用</strong>:<strong>确保即使 primary 故障切换,新 view 也能恢复 prepared 状态对应的决议</strong>——这是 Commit 阶段的核心,它保证了<strong>跨 view 的一致性</strong>。</p><h3 id="_3-3-为什么是三阶段不是两阶段" tabindex="-1">3.3 为什么是三阶段不是两阶段 <a class="header-anchor" href="#_3-3-为什么是三阶段不是两阶段" aria-label="Permalink to &quot;3.3 为什么是三阶段不是两阶段&quot;">​</a></h3><p><strong>直觉</strong>:</p><ul><li><strong>Pre-prepare</strong>:primary 提议顺序(可能撒谎)</li><li><strong>Prepare</strong>:副本互相对齐&quot;我们都看到 primary 说了什么&quot;(消除撒谎)</li><li><strong>Commit</strong>:副本互相对齐&quot;我们都已 prepared&quot;(保证 view 切换后仍可恢复)</li></ul><p><strong>少一个阶段会怎样</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>只两阶段(只 Pre-prepare + Prepare):</span></span>
<span class="line"><span>    某副本 prepared 后立刻 execute</span></span>
<span class="line"><span>    但其他副本可能还没 prepared</span></span>
<span class="line"><span>    primary 故障 → 新 view 选举 → 新 view 不知道这个 prepared 状态 → 可能选出冲突 request</span></span>
<span class="line"><span>    → 违反一致性</span></span></code></pre></div><p><strong>所以 Commit 阶段是为了&quot;view change 后能恢复 prepared 状态&quot;</strong>——这是 PBFT 跟 Raft 最大的区别(Raft 是两阶段)。</p><h3 id="_3-4-view-change-主切换" tabindex="-1">3.4 view change(主切换) <a class="header-anchor" href="#_3-4-view-change-主切换" aria-label="Permalink to &quot;3.4 view change(主切换)&quot;">​</a></h3><p>如果 primary 挂了 / 撒谎 / 太慢,副本要切 view:</p><ol><li>副本本地超时(类 Raft election timeout)</li><li>副本发 <code>&lt;VIEW-CHANGE, new_view, prepared_set&gt;</code>(带上自己已 prepared 的 request)</li><li>新 view 的 primary 收集 2f+1 个 view-change 消息 → 发 NEW-VIEW</li><li>新 primary 用 prepared_set 重做未完成的 request</li></ol><p><strong>复杂度</strong>:<strong>view change 是 PBFT 最复杂的部分</strong>——要确保所有已 commit 的 request 在新 view 中保留,所有未 prepared 的 request 可以重新提议。</p><h3 id="_3-5-pbft-的-o-n2-消息复杂度" tabindex="-1">3.5 PBFT 的 O(N²) 消息复杂度 <a class="header-anchor" href="#_3-5-pbft-的-o-n2-消息复杂度" aria-label="Permalink to &quot;3.5 PBFT 的 O(N²) 消息复杂度&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pre-prepare:N - 1 条 (primary → 各副本)</span></span>
<span class="line"><span>Prepare:每个副本广播给其他 N - 1 个 → N × (N-1) 条</span></span>
<span class="line"><span>Commit:同理 → N × (N-1) 条</span></span>
<span class="line"><span></span></span>
<span class="line"><span>总计:O(N²)</span></span></code></pre></div><p><strong>N = 4 时 24 条消息,N = 100 时 19800 条</strong>——<strong>这是 PBFT 在大规模场景(公链)的硬伤</strong>。</p><hr><h2 id="四、hotstuff-o-n-的现代-bft" tabindex="-1">四、HotStuff:O(N) 的现代 BFT <a class="header-anchor" href="#四、hotstuff-o-n-的现代-bft" aria-label="Permalink to &quot;四、HotStuff:O(N) 的现代 BFT&quot;">​</a></h2><p>HotStuff(Yin et al., 2019,Facebook Libra 用)是 PBFT 二十年后的重要改进。<strong>核心思想:用线性消息复杂度 + 链式 commit + threshold signature</strong>。</p><h3 id="_4-1-关键优化-链式-bft-chained-hotstuff" tabindex="-1">4.1 关键优化:链式 BFT(Chained HotStuff) <a class="header-anchor" href="#_4-1-关键优化-链式-bft-chained-hotstuff" aria-label="Permalink to &quot;4.1 关键优化:链式 BFT(Chained HotStuff)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PBFT:三阶段对每条 request 独立完成</span></span>
<span class="line"><span>HotStuff:把多条 request 串成链,新 request 的 Prepare 阶段顺带完成上一条的 Commit</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Block N:    Prepare ─▶ Pre-commit ─▶ Commit ─▶ Decide</span></span>
<span class="line"><span>Block N+1:           Prepare ─▶ Pre-commit ─▶ Commit ─▶ Decide</span></span>
<span class="line"><span>Block N+2:                    Prepare ─▶ Pre-commit ─▶ Commit ─▶ Decide</span></span>
<span class="line"><span>                              </span></span>
<span class="line"><span>                              ▲</span></span>
<span class="line"><span>                              4 个连续 block 流水线化推进</span></span>
<span class="line"><span>                              每个 block 在前面那个的&quot;下一阶段&quot;时进入</span></span></code></pre></div><p><strong>好处</strong>:<strong>摊销开销,实际单 block 的延迟降到 4 个轮次,但消息可以批量</strong>。</p><h3 id="_4-2-关键优化-threshold-signature-门限签名" tabindex="-1">4.2 关键优化:Threshold Signature(门限签名) <a class="header-anchor" href="#_4-2-关键优化-threshold-signature-门限签名" aria-label="Permalink to &quot;4.2 关键优化:Threshold Signature(门限签名)&quot;">​</a></h3><p><strong>PBFT 痛点</strong>:副本之间互相广播 Prepare / Commit,每条消息要带签名 → N² 个签名验证。</p><p><strong>HotStuff 用 threshold signature</strong>:<strong>2f+1 个副本对一条消息签名,可以聚合成一个签名</strong>——leader 只需收集 2f+1 个签名,聚合后广播给所有副本,<strong>所有副本只需验证一个聚合签名</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>传统:每副本验证 2f+1 个签名,O(N²) 验签</span></span>
<span class="line"><span>HotStuff:每副本验证 1 个聚合签名,O(N) 通信</span></span></code></pre></div><p><strong>代价</strong>:门限签名需要预先做 DKG(Distributed Key Generation),节点加入退出复杂。</p><h3 id="_4-3-hotstuff-流程-简化" tabindex="-1">4.3 HotStuff 流程(简化) <a class="header-anchor" href="#_4-3-hotstuff-流程-简化" aria-label="Permalink to &quot;4.3 HotStuff 流程(简化)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>View N:</span></span>
<span class="line"><span>    Leader 收 commands → 提议 block</span></span>
<span class="line"><span>    阶段 1(prepare):leader 收 2f+1 个签名 → 形成 QC(Quorum Certificate)</span></span>
<span class="line"><span>    阶段 2(pre-commit):leader 用上一阶段 QC 提议 → 收 2f+1 → 新 QC</span></span>
<span class="line"><span>    阶段 3(commit):同上</span></span>
<span class="line"><span>    阶段 4(decide):同上 → 执行</span></span>
<span class="line"><span></span></span>
<span class="line"><span>四个阶段都是&quot;leader 广播 → 副本签名 → leader 聚合&quot;的模式</span></span>
<span class="line"><span>通信复杂度:O(N) 每副本(leader 收 N,副本只发 1 个给 leader)</span></span></code></pre></div><blockquote><p><strong>HotStuff 是 Libra(后改名 Diem)的共识基础,后被多个项目采用</strong>(Aptos / Sui / Flow 的早期都基于 HotStuff)。<strong>它在 PBFT 的安全性基础上,把消息复杂度从 O(N²) 降到 O(N),让 100+ 节点的 BFT 变得可行</strong>。</p></blockquote><hr><h2 id="五、tendermint-cosmos-工业级的-bft-pos" tabindex="-1">五、Tendermint / Cosmos:工业级的 BFT + PoS <a class="header-anchor" href="#五、tendermint-cosmos-工业级的-bft-pos" aria-label="Permalink to &quot;五、Tendermint / Cosmos:工业级的 BFT + PoS&quot;">​</a></h2><p>Tendermint 是 Jae Kwon 2014 年提出的 BFT 共识,<strong>PBFT 改进 + leader 轮换</strong>,后来发展成 <strong>Cosmos</strong> 区块链生态的核心。</p><h3 id="_5-1-设计要点" tabindex="-1">5.1 设计要点 <a class="header-anchor" href="#_5-1-设计要点" aria-label="Permalink to &quot;5.1 设计要点&quot;">​</a></h3><table tabindex="0"><thead><tr><th>特征</th><th>Tendermint 做法</th></tr></thead><tbody><tr><td><strong>算法基础</strong></td><td>PBFT + 改进(2 阶段 prepare + pre-commit)</td></tr><tr><td><strong>Leader</strong></td><td><strong>每轮轮换</strong>(round-robin / weighted by stake)</td></tr><tr><td><strong>故障切换</strong></td><td>内置(轮次超时自动换 leader)</td></tr><tr><td><strong>节点身份</strong></td><td><strong>PoS(Proof of Stake)</strong> —— 抵押币当 validator</td></tr><tr><td><strong>拜占庭容错</strong></td><td>严格 N ≥ 3f+1</td></tr><tr><td><strong>最终性</strong></td><td><strong>即时最终性(deterministic finality)</strong>—— 区块 commit 后不会回滚</td></tr></tbody></table><h3 id="_5-2-tendermint-三阶段-类-pbft" tabindex="-1">5.2 Tendermint 三阶段(类 PBFT) <a class="header-anchor" href="#_5-2-tendermint-三阶段-类-pbft" aria-label="Permalink to &quot;5.2 Tendermint 三阶段(类 PBFT)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Round R:</span></span>
<span class="line"><span>    Propose:本轮 leader 提议 block</span></span>
<span class="line"><span>    Prevote:validator 广播 prevote</span></span>
<span class="line"><span>    Precommit:收到 2f+1 prevote → 广播 precommit</span></span>
<span class="line"><span>    Commit:收到 2f+1 precommit → 区块 commit,进入下一 height</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如果本轮 leader 挂或超时:</span></span>
<span class="line"><span>    自动进入下一轮(R+1),换 leader 重试</span></span></code></pre></div><p><strong>跟 PBFT 比的区别</strong>:</p><ul><li>PBFT 是<strong>有故障才换 leader</strong>(view change 是事件触发)</li><li>Tendermint 是<strong>每轮都换 leader</strong>(round-robin)——降低单 leader 性能压力,均衡 validator</li></ul><h3 id="_5-3-bft-pos-的妙处" tabindex="-1">5.3 BFT + PoS 的妙处 <a class="header-anchor" href="#_5-3-bft-pos-的妙处" aria-label="Permalink to &quot;5.3 BFT + PoS 的妙处&quot;">​</a></h3><p><strong>PoS 解决了&quot;谁是 validator&quot;问题</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>传统 PBFT:N 个 validator 是固定配置,管理员决定</span></span>
<span class="line"><span>        → 适合联盟链(已知参与方)</span></span>
<span class="line"><span>        → 不适合公链(谁都能加入)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>PoS:任何持币者都可以抵押币成为 validator</span></span>
<span class="line"><span>    抵押越多投票权越大(stake-weighted)</span></span>
<span class="line"><span>    作恶被罚没抵押币(slashing)</span></span>
<span class="line"><span>    → 适合公链,有经济激励对抗作恶</span></span></code></pre></div><p><strong>Cosmos / Tendermint = 公链版 PBFT</strong>:</p><ul><li>BFT 保证强一致(N ≥ 3f+1 的 voting power)</li><li>PoS 保证 validator 集合开放且有反作恶激励</li><li>即时最终性:区块 commit 后<strong>绝对不会回滚</strong>(对比比特币的&quot;概率最终性&quot;)</li></ul><h3 id="_5-4-工业应用" tabindex="-1">5.4 工业应用 <a class="header-anchor" href="#_5-4-工业应用" aria-label="Permalink to &quot;5.4 工业应用&quot;">​</a></h3><ul><li><strong>Cosmos Hub</strong>(ATOM)、Binance Chain、Terra(经典)、Crypto.com Chain</li><li><strong>Hyperledger Burrow</strong> 早期用 Tendermint</li><li><strong>大量 Cosmos SDK 链</strong>:几十个独立链都用同一套共识</li></ul><hr><h2 id="六、pbft-不是公链共识" tabindex="-1">六、PBFT 不是公链共识 <a class="header-anchor" href="#六、pbft-不是公链共识" aria-label="Permalink to &quot;六、PBFT 不是公链共识&quot;">​</a></h2><p><strong>很多人混淆</strong>:PoW / PoS 公链是&quot;拜占庭容错的&quot;,但<strong>PoW / PoS 不是 PBFT 家族</strong>。</p><h3 id="_6-1-pow-pos-的本质" tabindex="-1">6.1 PoW / PoS 的本质 <a class="header-anchor" href="#_6-1-pow-pos-的本质" aria-label="Permalink to &quot;6.1 PoW / PoS 的本质&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PoW(Bitcoin):</span></span>
<span class="line"><span>    所有节点竞争算 hash,赢者打包区块</span></span>
<span class="line"><span>    最长链 = 真链(probabilistic finality)</span></span>
<span class="line"><span>    6 个块确认后,逆转概率 &lt; 10^-9</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>PoS(Ethereum 2.0):</span></span>
<span class="line"><span>    抵押币的节点按权重轮流出块</span></span>
<span class="line"><span>    新块被多数 validator 投票后视为 finalized</span></span>
<span class="line"><span>    finalized 后逆转需要超过 1/3 stake 同时作恶(惩罚极重)</span></span></code></pre></div><p><strong>两者都不是严格 BFT</strong>——它们是<strong>经济学 + 概率论 + 部分共识</strong>的组合。</p><h3 id="_6-2-pow-pos-vs-bft-对比" tabindex="-1">6.2 PoW/PoS vs BFT 对比 <a class="header-anchor" href="#_6-2-pow-pos-vs-bft-对比" aria-label="Permalink to &quot;6.2 PoW/PoS vs BFT 对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>PBFT/HotStuff/Tendermint</th><th>Bitcoin PoW</th><th>Ethereum PoS</th></tr></thead><tbody><tr><td><strong>最终性</strong></td><td><strong>即时确定</strong></td><td><strong>概率性</strong>(6 块 ≈ 1 小时)</td><td>混合(Casper finality, ≈ 12 分钟)</td></tr><tr><td><strong>TPS</strong></td><td>1k - 10k+</td><td>≈ 7</td><td>≈ 15-30(L1)</td></tr><tr><td><strong>节点数上限</strong></td><td>数十到数百(消息复杂度限制)</td><td>数万</td><td>数十万(validator)</td></tr><tr><td><strong>节点身份</strong></td><td>已知(联盟)或 stake-weighted</td><td>匿名,任何人挖</td><td>抵押 32 ETH</td></tr><tr><td><strong>能耗</strong></td><td>极低(普通服务器)</td><td>巨大(挖矿)</td><td>低</td></tr><tr><td><strong>抵御 51% 攻击</strong></td><td>f &lt; N/3 拜占庭即可</td><td>需 51% 算力</td><td>需 1/3 stake</td></tr></tbody></table><blockquote><p><strong>公链 PoW/PoS 是为&quot;无许可、大规模、匿名节点&quot;设计的</strong>,<strong>性能远不如 PBFT</strong>(因为节点身份未知,信任成本高)。<strong>联盟链 / 容灾级金融用 PBFT/Tendermint,公链生态用 PoW/PoS</strong>——<strong>这是商业模型决定的,不是技术好坏</strong>。</p></blockquote><hr><h2 id="七、几个-bft-协议对比" tabindex="-1">七、几个 BFT 协议对比 <a class="header-anchor" href="#七、几个-bft-协议对比" aria-label="Permalink to &quot;七、几个 BFT 协议对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>协议</th><th>年份</th><th>阶段数</th><th>消息复杂度</th><th>Leader</th><th>最终性</th><th>工业代表</th></tr></thead><tbody><tr><td><strong>拜占庭将军问题</strong></td><td>1982</td><td>理论</td><td>O(N^(f+1))</td><td>—</td><td>—</td><td>学术</td></tr><tr><td><strong>PBFT</strong></td><td>1999</td><td>3</td><td>O(N²)</td><td>静态</td><td>即时</td><td>Hyperledger Fabric(Kafka 模式之外)</td></tr><tr><td><strong>Zyzzyva</strong></td><td>2007</td><td>推测执行</td><td>O(N) 乐观</td><td>静态</td><td>即时</td><td>未广泛</td></tr><tr><td><strong>Tendermint</strong></td><td>2014</td><td>3(类 PBFT)</td><td>O(N²)</td><td><strong>轮换</strong></td><td>即时</td><td><strong>Cosmos 生态</strong></td></tr><tr><td><strong>HotStuff</strong></td><td>2019</td><td>4(链式)</td><td><strong>O(N)</strong></td><td>轮换</td><td>即时</td><td><strong>Diem / Aptos / Sui</strong></td></tr><tr><td><strong>DiemBFT / LibraBFT</strong></td><td>2019</td><td>HotStuff 变体</td><td>O(N)</td><td>轮换</td><td>即时</td><td>Diem(已停)</td></tr><tr><td><strong>Aleph / Narwhal-Bullshark</strong></td><td>2021+</td><td>DAG-based</td><td>复杂</td><td>—</td><td>即时</td><td>Sui / Aptos 后续</td></tr></tbody></table><blockquote><p><strong>趋势:从 PBFT 的 O(N²) 走向 HotStuff 的 O(N),从静态 leader 走向轮换/无 leader,从批量打包走向 DAG 并行</strong>。<strong>核心目标:让 BFT 在 100+ 节点规模下仍能跑出几千 TPS</strong>。</p></blockquote><hr><h2 id="八、pbft-在哪里被工业用了" tabindex="-1">八、PBFT 在哪里被工业用了 <a class="header-anchor" href="#八、pbft-在哪里被工业用了" aria-label="Permalink to &quot;八、PBFT 在哪里被工业用了&quot;">​</a></h2><table tabindex="0"><thead><tr><th>系统</th><th>用 PBFT 家族</th><th>备注</th></tr></thead><tbody><tr><td><strong>Hyperledger Fabric</strong></td><td>可选 PBFT(早期);新版 Raft 模式(crash-only)</td><td>联盟链;<strong>Raft 模式不是 BFT,只防 crash</strong></td></tr><tr><td><strong>Hyperledger Sawtooth</strong></td><td>PoET / Raft / 可插拔</td><td>联盟链</td></tr><tr><td><strong>R3 Corda</strong></td><td>Notary 可选 BFT(Raft 也行)</td><td>金融联盟</td></tr><tr><td><strong>Quorum / GoQuorum</strong></td><td>IBFT / QBFT(类 PBFT)</td><td>以太坊衍生联盟链</td></tr><tr><td><strong>Cosmos / Cosmos SDK 链</strong></td><td>Tendermint</td><td>公链 + 联盟链都用</td></tr><tr><td><strong>Diem / Aptos / Sui</strong></td><td>LibraBFT / DiemBFT(HotStuff 系)</td><td>公链</td></tr><tr><td><strong>比特币 / 以太坊</strong></td><td><strong>不是 PBFT,是 PoW/PoS</strong></td><td>公链</td></tr><tr><td><strong>传统银行清算系统</strong></td><td>多用 Raft + 多重审计,<strong>几乎不用 BFT</strong></td><td>银行间网络可信度高</td></tr></tbody></table><p><strong>注意</strong>:<strong>Hyperledger Fabric 早期支持 PBFT,但社区主推的是 Raft</strong>(crash-only 排序服务)——<strong>因为联盟链的 validator 节点通常由参与方运维,虽然互不信任,但拜占庭故障的实际概率很低,Raft 性能更好</strong>。</p><blockquote><p><strong>这反映了一个工业现实</strong>:<strong>真正用 BFT 的场景比想象中少</strong>。即使是号称&quot;防拜占庭&quot;的联盟链,<strong>很多落地实现也降级用 Raft + 业务层签名 + 审计</strong>——<strong>纯算法层面的 BFT 用得不多</strong>。</p></blockquote><hr><h2 id="九、什么时候真的需要-bft" tabindex="-1">九、什么时候真的需要 BFT <a class="header-anchor" href="#九、什么时候真的需要-bft" aria-label="Permalink to &quot;九、什么时候真的需要 BFT&quot;">​</a></h2><h3 id="_9-1-真的需要-bft-的场景" tabindex="-1">9.1 真的需要 BFT 的场景 <a class="header-anchor" href="#_9-1-真的需要-bft-的场景" aria-label="Permalink to &quot;9.1 真的需要 BFT 的场景&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ 公链(无许可,匿名节点)</span></span>
<span class="line"><span>    Bitcoin / Ethereum / Cosmos / Solana ...</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>✅ 联盟链(多方互不信任,有明确法律合规)</span></span>
<span class="line"><span>    跨银行清算、供应链溯源、数字身份联盟</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>✅ 高安全要求的多方协作</span></span>
<span class="line"><span>    电子选举、隐私计算的协调层</span></span></code></pre></div><h3 id="_9-2-不需要-bft-的场景-99-的业务" tabindex="-1">9.2 不需要 BFT 的场景(99% 的业务) <a class="header-anchor" href="#_9-2-不需要-bft-的场景-99-的业务" aria-label="Permalink to &quot;9.2 不需要 BFT 的场景(99% 的业务)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>❌ 公司内部集群(节点同属一家公司)</span></span>
<span class="line"><span>    用 Raft / Paxos / ZAB,信任内部运维</span></span>
<span class="line"><span></span></span>
<span class="line"><span>❌ 大多数互联网服务</span></span>
<span class="line"><span>    高可用足够,拜占庭故障极少发生</span></span>
<span class="line"><span></span></span>
<span class="line"><span>❌ 一般金融系统(银行内部 / 支付公司内部)</span></span>
<span class="line"><span>    强一致 + 审计 + 对账,不需要 BFT 性能开销</span></span>
<span class="line"><span></span></span>
<span class="line"><span>❌ 中间件 / 协调服务</span></span>
<span class="line"><span>    etcd / Consul / ZK 都不是 BFT</span></span></code></pre></div><h3 id="_9-3-bft-的代价" tabindex="-1">9.3 BFT 的代价 <a class="header-anchor" href="#_9-3-bft-的代价" aria-label="Permalink to &quot;9.3 BFT 的代价&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>Raft / Paxos</th><th>PBFT</th></tr></thead><tbody><tr><td><strong>节点数(容忍 1 节点故障)</strong></td><td>3</td><td><strong>4</strong></td></tr><tr><td><strong>消息复杂度</strong></td><td>O(N)</td><td>O(N²)</td></tr><tr><td><strong>典型延迟</strong></td><td>1-10ms</td><td>30-100ms+</td></tr><tr><td><strong>典型 TPS</strong></td><td>万级-十万级</td><td>千级-万级</td></tr><tr><td><strong>代码复杂度</strong></td><td>中(几千行 Raft 库)</td><td><strong>高</strong>(view change + 签名 + 拜占庭防御)</td></tr><tr><td><strong>运维复杂度</strong></td><td>中</td><td><strong>高</strong>(签名密钥管理、PoS slashing 逻辑)</td></tr></tbody></table><blockquote><p><strong>粗略估计</strong>:<strong>BFT 比 Raft 的工程开销大 3-5 倍</strong>——节点数、消息量、延迟、代码复杂度都翻倍以上。<strong>这是为什么 99% 的业务不用 BFT</strong>:<strong>多花 3 倍成本,换的是&quot;对抗你内部从不存在的攻击者&quot;</strong>。</p></blockquote><hr><h2 id="十、面试-思考时的常见错误" tabindex="-1">十、面试 / 思考时的常见错误 <a class="header-anchor" href="#十、面试-思考时的常见错误" aria-label="Permalink to &quot;十、面试 / 思考时的常见错误&quot;">​</a></h2><h3 id="_10-1-「区块链-拜占庭容错」" tabindex="-1">10.1 「区块链 = 拜占庭容错」 <a class="header-anchor" href="#_10-1-「区块链-拜占庭容错」" aria-label="Permalink to &quot;10.1 「区块链 = 拜占庭容错」&quot;">​</a></h3><p><strong>部分对</strong>。<strong>公链是 BFT 的实际应用</strong>,但<strong>它们用的算法(PoW/PoS)不是经典 BFT,而是经济学 + 概率论的混合</strong>。<strong>说&quot;区块链用 PBFT&quot;是错的</strong>(只有联盟链和部分公链如 Cosmos 用 PBFT 家族)。</p><h3 id="_10-2-「raft-也能拜占庭」" tabindex="-1">10.2 「Raft 也能拜占庭」 <a class="header-anchor" href="#_10-2-「raft-也能拜占庭」" aria-label="Permalink to &quot;10.2 「Raft 也能拜占庭」&quot;">​</a></h3><p><strong>错</strong>。Raft 假设 crash-only,<strong>一个撒谎的 leader 能让所有 follower 接受错误日志</strong>——<strong>Raft 不验证消息内容,也没有签名机制</strong>。要让 Raft 抗拜占庭,要叠<strong>消息签名 + multi-party 验证</strong>,但这就不是 Raft 了。</p><h3 id="_10-3-「n-≥-3f-1-是因为多数派要-2-3」" tabindex="-1">10.3 「N ≥ 3f+1 是因为多数派要 &gt; 2/3」 <a class="header-anchor" href="#_10-3-「n-≥-3f-1-是因为多数派要-2-3」" aria-label="Permalink to &quot;10.3 「N ≥ 3f+1 是因为多数派要 &gt; 2/3」&quot;">​</a></h3><p><strong>部分对</strong>。<strong>更精确的说法是</strong>:<strong>多数派之间必有&quot;诚实节点交集&quot;,且交集必须够大支撑下一轮决策</strong>——3f+1 是数学下界。</p><h3 id="_10-4-「bft-性能差-→-不用-bft」" tabindex="-1">10.4 「BFT 性能差 → 不用 BFT」 <a class="header-anchor" href="#_10-4-「bft-性能差-→-不用-bft」" aria-label="Permalink to &quot;10.4 「BFT 性能差 → 不用 BFT」&quot;">​</a></h3><p><strong>错位</strong>。BFT 性能差是为 BFT 场景准备的代价。<strong>在不需要拜占庭抗性的场景,用 Raft 性能远好于 BFT,这是正确选型,不是 BFT 失败</strong>。</p><h3 id="_10-5-「pow-是-bft」" tabindex="-1">10.5 「PoW 是 BFT」 <a class="header-anchor" href="#_10-5-「pow-是-bft」" aria-label="Permalink to &quot;10.5 「PoW 是 BFT」&quot;">​</a></h3><p><strong>错</strong>。PoW <strong>没有 finality guarantee</strong>(只是概率最终性),理论上<strong>任何时候都可能被更长链回滚</strong>。<strong>经典 BFT 定义要求 finality + safety after commit</strong>——PoW 不满足。<strong>所以严格地说,Bitcoin 不是 BFT 系统</strong>,而是&quot;实践中安全的概率共识&quot;。</p><hr><h2 id="十一、真实事件-bft-没救的攻击场景" tabindex="-1">十一、真实事件:BFT 没救的攻击场景 <a class="header-anchor" href="#十一、真实事件-bft-没救的攻击场景" aria-label="Permalink to &quot;十一、真实事件:BFT 没救的攻击场景&quot;">​</a></h2><p>即使用了 BFT,也不能防一切:</p><h3 id="_11-1-51-攻击-算力-stake-集中" tabindex="-1">11.1 51% 攻击(算力 / stake 集中) <a class="header-anchor" href="#_11-1-51-攻击-算力-stake-集中" aria-label="Permalink to &quot;11.1 51% 攻击(算力 / stake 集中)&quot;">​</a></h3><p><strong>BFT 假设 f &lt; N/3 的拜占庭节点</strong>——<strong>如果攻击者控制超过 1/3,可以阻止共识(liveness 攻击);超过 2/3,可以做任意事(safety 攻击)</strong>。</p><ul><li>Ethereum Classic 多次 51% 攻击(PoW)</li><li>小型 Cosmos 链如果 validator 集中,也面临 stake 集中风险</li></ul><h3 id="_11-2-长程攻击-long-range-attack" tabindex="-1">11.2 长程攻击(Long-Range Attack) <a class="header-anchor" href="#_11-2-长程攻击-long-range-attack" aria-label="Permalink to &quot;11.2 长程攻击(Long-Range Attack)&quot;">​</a></h3><p>PoS 系统特有的攻击——<strong>老的 validator 私钥泄露后,可以从早期分叉伪造一条更长的链</strong>。<strong>对策</strong>:weak subjectivity checkpoint(节点定期从可信源获取近期区块作锚点)。</p><h3 id="_11-3-跨链桥被黑" tabindex="-1">11.3 跨链桥被黑 <a class="header-anchor" href="#_11-3-跨链桥被黑" aria-label="Permalink to &quot;11.3 跨链桥被黑&quot;">​</a></h3><p><strong>跨链桥本质是多方签名(BFT)+ 中继</strong>——<strong>Ronin Bridge / Wormhole / Nomad 都被黑过,损失数亿美元</strong>。<strong>根本原因不是 BFT 算法漏洞,而是 multi-sig 私钥管理 / 签名验证逻辑 bug</strong>——<strong>BFT 协议正确,代码实现可能错</strong>。</p><h3 id="_11-4-客户端漏洞" tabindex="-1">11.4 客户端漏洞 <a class="header-anchor" href="#_11-4-客户端漏洞" aria-label="Permalink to &quot;11.4 客户端漏洞&quot;">​</a></h3><p><strong>协议 BFT 不代表实现 BFT</strong>——<strong>节点软件本身的 bug(如 DoS、内存安全)可以让 f 个节点同时挂,等效于拜占庭故障</strong>。<strong>多客户端实现(Geth / Erigon / Nethermind 等)是公链对抗这一点的方式</strong>。</p><hr><h2 id="十二、踩坑提醒" tabindex="-1">十二、踩坑提醒 <a class="header-anchor" href="#十二、踩坑提醒" aria-label="Permalink to &quot;十二、踩坑提醒&quot;">​</a></h2><ol><li><strong>以为自己需要 BFT</strong> —— 99% 的内部业务用 Raft 就够,<strong>别因为&quot;高大上&quot;上 BFT,工程复杂度爆炸</strong></li><li><strong>联盟链选错共识</strong> —— Hyperledger Fabric 的 Raft 排序服务 ≠ BFT,<strong>真要拜占庭抗性,要选 PBFT/SmartBFT/etc.</strong></li><li><strong>N ≥ 3f+1 配少了</strong> —— 4 个节点(f=1)看起来够,但只容忍 1 节点故障 + 0 拜占庭,实际几乎没用;<strong>生产至少 7 节点(f=2)</strong></li><li><strong>消息复杂度爆炸</strong> —— PBFT 在 N &gt; 30 时 O(N²) 不可接受,<strong>大规模上 HotStuff / Tendermint</strong></li><li><strong>不验证消息签名</strong> —— BFT 协议的核心是验证每条消息的签名,<strong>忘了验证 = 退化成 Raft 假设(假设节点诚实)</strong></li><li><strong>门限签名密钥管理混乱</strong> —— HotStuff / Cosmos 用门限签名,<strong>密钥泄露会破坏 BFT 假设</strong>,密钥管理是工程重点</li><li><strong>混淆 finality</strong> —— PoW 是概率最终性,PBFT 是即时最终性,<strong>业务侧&quot;区块确认后是否能回滚&quot;完全不同</strong></li><li><strong>PoS slashing 逻辑没设计好</strong> —— 抵押币没收逻辑写错,<strong>作恶节点不受惩罚,等于没有经济安全</strong></li><li><strong>以为公链 BFT 抗一切</strong> —— 51% / 长程 / 桥攻击都能击穿,<strong>BFT 是算法层,不是系统层</strong></li><li><strong>拜占庭跟&quot;故障 = 攻击&quot;画等号</strong> —— <strong>硬件错误也算拜占庭</strong>(磁盘静默损坏、内存翻转),<strong>金融级系统即使无攻击也可能想要 BFT 处理硬件错</strong></li><li><strong>BFT 系统的客户端不验证回复</strong> —— <strong>PBFT client 应该等 f+1 个相同回复才信</strong>,只信 1 个回复 = 完全没用</li></ol><hr><h2 id="十三、收束-这一层的全景" tabindex="-1">十三、收束:这一层的全景 <a class="header-anchor" href="#十三、收束-这一层的全景" aria-label="Permalink to &quot;十三、收束:这一层的全景&quot;">​</a></h2><p>到这里,<strong>共识协议这一层(09-15 篇)讲完了</strong>——</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>        FLP 不可能定理(异步 + 一个故障 = 共识不可能)</span></span>
<span class="line"><span>            │</span></span>
<span class="line"><span>            ▼</span></span>
<span class="line"><span>        加上&quot;部分同步&quot;假设(实际网络通常是 partial sync)</span></span>
<span class="line"><span>            │</span></span>
<span class="line"><span>        ┌───┴───┬─────┬───────┐</span></span>
<span class="line"><span>        ▼       ▼     ▼       ▼</span></span>
<span class="line"><span>    Crash 模型 → Paxos → Raft → ZAB(为 ZK 定制)</span></span>
<span class="line"><span>                       │       </span></span>
<span class="line"><span>                       ├── multi-Raft(规模化)</span></span>
<span class="line"><span>                       │       </span></span>
<span class="line"><span>                       └── EPaxos(无 leader,跨地域优化)</span></span>
<span class="line"><span>                       </span></span>
<span class="line"><span>                       ▼</span></span>
<span class="line"><span>                       </span></span>
<span class="line"><span>        Byzantine 模型 → PBFT(1999)</span></span>
<span class="line"><span>                       → HotStuff(O(N) 改进)</span></span>
<span class="line"><span>                       → Tendermint(BFT + PoS,Cosmos)</span></span>
<span class="line"><span>                       → PoW/PoS(概率最终性,公链)</span></span></code></pre></div><p><strong>共识协议的工程图景</strong>:</p><ul><li><strong>Raft 是当下绝对主流</strong>——95% 的新系统选它</li><li><strong>Paxos 留在老牌系统</strong>——Google 内部、Cassandra LWT、SQL Server</li><li><strong>ZAB 留在 ZK</strong>——Hadoop 时代的协调王,新时代被 Raft 替代</li><li><strong>EPaxos 是理论王者</strong>——工业落地几乎为 0</li><li><strong>PBFT/HotStuff/Tendermint 在联盟链 + 公链</strong>——99% 的业务用不上</li></ul><p><strong>这一层的核心教训</strong>:</p><ol><li><strong>没有银弹</strong>——每个协议都是在「安全性 / 可用性 / 性能 / 复杂度」上做权衡</li><li><strong>简单胜过完美</strong>——Raft 的胜利证明,<strong>易实现易理解的协议比理论最优的协议更重要</strong></li><li><strong>场景决定选型</strong>——拜占庭场景上 BFT,crash 场景上 Raft,<strong>互不替代,各司其职</strong></li><li><strong>理论与工程之间巨大鸿沟</strong>——Paxos 论文 1989,工业广泛使用要等 Raft 2014;PBFT 论文 1999,工业大规模应用要等区块链 2014+</li><li><strong>再好的算法实现得错也白搭</strong>——<strong>Jepsen 报告里几乎每个共识库都被找到过 bug</strong></li></ol><p><strong>下一篇我们离开共识层,进入&quot;一致性模型&quot;这一层</strong>(16-19 篇)——共识协议保证了&quot;日志一致&quot;,但<strong>应用程序看到的&quot;数据一致&quot;还有 5-6 个档位</strong>:Linearizability、Sequential、Causal、Eventual...... <strong>共识只是手段,一致性模型是用户看到的承诺</strong>。<strong>99% 的&quot;诡异分布式 bug&quot;是一致性模型选错了</strong>——这一层会让你看清&quot;为什么 Redis Cluster 不是真线性一致&quot;、&quot;为什么 DynamoDB 的强一致读不是真线性一致&quot;。</p><blockquote><p><strong>看完这五篇共识(11-15),你应该能在白板上画出 Paxos / Multi-Paxos / Raft / ZAB / PBFT 的状态机和流程,能回答&quot;何时该选哪个&quot;</strong>。<strong>做到这点,你就读懂了所有现代协调服务、分布式数据库、区块链系统的底层秘密</strong>。</p></blockquote><hr><h2 id="第三层小结-09-15-共识层" tabindex="-1">第三层小结(09-15 共识层) <a class="header-anchor" href="#第三层小结-09-15-共识层" aria-label="Permalink to &quot;第三层小结(09-15 共识层)&quot;">​</a></h2><p><strong>这一层是分布式系统理论的最值钱七篇</strong>,因为:</p><ul><li><strong>几乎所有分布式中间件的底都在这一层</strong>——你天天用的 etcd / ZK / Kafka / TiDB / CockroachDB / MongoDB / Consul,<strong>底下要么 Raft 要么 Paxos 要么 ZAB</strong></li><li><strong>故障排查最常落到这一层</strong>——脑裂、leader 切换抖动、commit 卡住、follower 落后,<strong>全是共识协议的某条不变量被工程实现破坏</strong></li><li><strong>面试的&quot;硬核区&quot;</strong> —— 高级架构师 / 中间件岗位的核心面试题就在这层</li></ul><p><strong>七篇的最小记忆图</strong>:</p><table tabindex="0"><thead><tr><th>篇</th><th>核心一句话</th></tr></thead><tbody><tr><td>09 FLP</td><td><strong>异步 + 一个故障 = 共识理论上不可能</strong></td></tr><tr><td>10 复制三态</td><td><strong>主从 / 多主 / 无主三选一,Quorum 是无主的灵魂</strong></td></tr><tr><td>11 Paxos</td><td><strong>prepare + accept 两阶段,数学完美,论文难懂</strong></td></tr><tr><td>12 Multi-Paxos</td><td><strong>加 leader + 日志,工程化的 Paxos,Chubby 在用</strong></td></tr><tr><td>13 Raft</td><td><strong>Paxos 的&quot;易读版&quot;,新系统首选,etcd 在用</strong></td></tr><tr><td>14 ZAB / EPaxos</td><td><strong>ZK 用的 ZAB(严格 FIFO);EPaxos 无 leader 理论最优,工业极少</strong></td></tr><tr><td>15 拜占庭容错</td><td><strong>节点会撒谎时,N ≥ 3f+1;PBFT/HotStuff 在公链 / 联盟链</strong></td></tr></tbody></table><p><strong>这七篇之后,你不再害怕任何分布式中间件的源码</strong>——<strong>翻到 raft.go / paxos.cc / zab.java 就知道在保护哪条不变量,出 bug 时知道往哪查</strong>。</p><hr><p>下一篇:<code>16-一致性模型谱.md</code>,进入第四层。<strong>共识保证日志一致,但用户看到的&quot;数据一致&quot;是另一回事</strong>——Linearizability / Sequential / Causal / Read-Your-Writes / Eventual,一致性是个<strong>光谱</strong>,<strong>选错档位 = 99% 的诡异分布式 bug</strong>。</p>`,167)])])}const u=s(r,[["render",e]]);export{h as __pageData,u as default};
